26	bool JSONFFIEngine::ChatCompletion(std::string request_json_str, std::string request_id) {
27	  bool success = this->AddRequest(request_json_str, request_id);
28	  if (!success) {
29	    this->StreamBackError(request_id);
30	  }
31	  return success;
32	}
