34	void JSONFFIEngine::StreamBackError(std::string request_id) {
35	  ChatCompletionMessage delta;
36	  delta.content = this->err_;
37	  delta.role = "assistant";
38	
39	  ChatCompletionStreamResponseChoice choice;
40	  choice.finish_reason = FinishReason::error;
41	  choice.index = 0;
42	  choice.delta = delta;
43	
44	  ChatCompletionStreamResponse response;
45	  response.id = request_id;
46	  response.choices = std::vector<ChatCompletionStreamResponseChoice>{choice};
47	  response.model = "json_ffi";  // TODO: Return model name from engine (or from args)
48	  response.system_fingerprint = "";
49	
50	  tvm::ffi::json::Array response_arr;
51	  response_arr.push_back(response.AsJSON());
52	
53	  // now stream back the final usage block, which is required.
54	  // NOTE: always stream back final usage block as it is an
55	  // invariant of the system
56	  response.choices.clear();
57	  tvm::ffi::json::Object dummy_usage;
58	  dummy_usage.Set("prompt_tokens", static_cast<int64_t>(0));
59	  dummy_usage.Set("completion_tokens", static_cast<int64_t>(0));
60	  dummy_usage.Set("total_tokens", static_cast<int64_t>(0));
61	  response.usage = tvm::ffi::json::Value(dummy_usage);
62	  response_arr.push_back(response.AsJSON());
63	
64	  std::string stream_back_json = tvm::ffi::json::Stringify(response_arr);
65	  this->request_stream_callback_(stream_back_json);
66	}
67	
68	bool JSONFFIEngine::AddRequest(std::string request_json_str, std::string request_id) {
69	  Result<ChatCompletionRequest> request_res = ChatCompletionRequest::FromJSON(request_json_str);
70	  if (request_res.IsErr()) {
71	    err_ = request_res.UnwrapErr();
72	    return false;
73	  }
74	  ChatCompletionRequest request = request_res.Unwrap();
75	  Array<Data> inputs;
76	  Array<String> stop_strs;
77	  bool is_special_request =
78	      (request.debug_config.has_value() &&
79	       request.debug_config.value().special_request != SpecialRequestKind::kNone);
80	  // special request does not have to go through prompt construction
81	  if (!is_special_request) {
82	    // get prompt: note, assistant was appended in the end.
83	    Result<std::vector<Data>> inputs_obj =
84	        CreatePrompt(this->conv_template_, request, this->model_config_, this->device_);
85	    if (inputs_obj.IsErr()) {
86	      err_ = inputs_obj.UnwrapErr();
87	      return false;
88	    }
89	    inputs = inputs_obj.Unwrap();
90	
91	    stop_strs.reserve(this->conv_template_.stop_str.size());
92	    for (const std::string& stop_str : this->conv_template_.stop_str) {
93	      stop_strs.push_back(stop_str);
94	    }
95	    if (request.stop.has_value()) {
96	      stop_strs.reserve(stop_strs.size() + request.stop.value().size());
97	      for (const std::string& stop_str : request.stop.value()) {
98	        stop_strs.push_back(stop_str);
99	      }
100	    }
101	  }
102	  // create a generation config from request
103	  const auto& default_gen_cfg = default_generation_config_;
104	  auto gen_cfg = tvm::ffi::make_object<GenerationConfigNode>();
105	  gen_cfg->n = request.n;
106	  gen_cfg->temperature = request.temperature.value_or(default_gen_cfg->temperature);
107	  gen_cfg->top_p = request.top_p.value_or(default_gen_cfg->top_p);
108	  gen_cfg->frequency_penalty =
109	      request.frequency_penalty.value_or(default_gen_cfg->frequency_penalty);
110	  gen_cfg->presence_penalty = request.presence_penalty.value_or(default_gen_cfg->presence_penalty);
111	  gen_cfg->logprobs = request.logprobs;
112	  gen_cfg->top_logprobs = request.top_logprobs;
113	  gen_cfg->logit_bias = request.logit_bias.value_or(default_gen_cfg->logit_bias);
114	  gen_cfg->seed = request.seed.value_or(std::random_device{}());
115	  gen_cfg->max_tokens = request.max_tokens.value_or(default_gen_cfg->max_tokens);
116	  gen_cfg->stop_strs = std::move(stop_strs);
117	  gen_cfg->stop_token_ids = conv_template_.stop_token_ids;
118	  gen_cfg->response_format = request.response_format.value_or(ResponseFormat());
119	  gen_cfg->debug_config = request.debug_config.value_or(DebugConfig());
120	
121	  Result<GenerationConfig> res_gen_config = GenerationConfig::Validate(GenerationConfig(gen_cfg));
122	  if (res_gen_config.IsErr()) {
123	    err_ = res_gen_config.UnwrapErr();
124	    return false;
125	  }
126	
127	  Request engine_request(request_id, inputs, res_gen_config.Unwrap());
128	
129	  // setup request state
130	  RequestState rstate;
131	  rstate.model = request.model.value_or("");
132	  rstate.streamer.reserve(gen_cfg->n);
133	  for (int i = 0; i < gen_cfg->n; ++i) {
134	    rstate.streamer.push_back(TextStreamer(tokenizer_));
135	  }
136	  request_map_[request_id] = std::move(rstate);
137	
138	  this->engine_->AddRequest(engine_request);
139	  return true;
140	}
141	
142	bool JSONFFIEngine::Abort(std::string request_id) {
143	  this->engine_->AbortRequest(request_id);
144	  auto it = request_map_.find(request_id);
145	  if (it != request_map_.end()) {
146	    request_map_.erase(it);
147	  }
148	  return true;
149	}
150	
151	std::string JSONFFIEngine::GetLastError() { return err_; }
152	
153	void JSONFFIEngine::ExitBackgroundLoop() { this->engine_->ExitBackgroundLoop(); }
154	
155	JSONFFIEngine::~JSONFFIEngine() { this->ExitBackgroundLoop(); }
