157	class JSONFFIEngineImpl : public JSONFFIEngine, public ffi::ModuleObj {
158	 public:
159	  TVM_MODULE_VTABLE_BEGIN("mlc.json_ffi");
160	  TVM_MODULE_VTABLE_ENTRY("init_background_engine", &JSONFFIEngineImpl::InitBackgroundEngine);
161	  TVM_MODULE_VTABLE_ENTRY("reload", &JSONFFIEngineImpl::Reload);
162	  TVM_MODULE_VTABLE_ENTRY("unload", &JSONFFIEngineImpl::Unload);
163	  TVM_MODULE_VTABLE_ENTRY("reset", &JSONFFIEngineImpl::Reset);
164	  TVM_MODULE_VTABLE_ENTRY("chat_completion", &JSONFFIEngineImpl::ChatCompletion);
165	  TVM_MODULE_VTABLE_ENTRY("abort", &JSONFFIEngineImpl::Abort);
166	  TVM_MODULE_VTABLE_ENTRY("get_last_error", &JSONFFIEngineImpl::GetLastError);
167	  TVM_MODULE_VTABLE_ENTRY("run_background_loop", &JSONFFIEngineImpl::RunBackgroundLoop);
168	  TVM_MODULE_VTABLE_ENTRY("run_background_stream_back_loop",
169	                          &JSONFFIEngineImpl::RunBackgroundStreamBackLoop);
170	  TVM_MODULE_VTABLE_ENTRY("exit_background_loop", &JSONFFIEngineImpl::ExitBackgroundLoop);
171	  TVM_MODULE_VTABLE_END();
172	
173	  void InitBackgroundEngine(int device_type, int device_id,
174	                            Optional<Function> request_stream_callback) {
175	    DLDevice device{static_cast<DLDeviceType>(device_type), device_id};
176	    this->device_ = device;
177	    TVM_FFI_ICHECK(request_stream_callback.has_value())
178	        << "JSONFFIEngine requires request stream callback function, but it is not given.";
179	    this->request_stream_callback_ = request_stream_callback.value();
180	
181	    auto frequest_stream_callback_wrapper = [this](ffi::PackedArgs args, ffi::Any* ret) {
182	      TVM_FFI_ICHECK_EQ(args.size(), 1);
183	      Array<RequestStreamOutput> delta_outputs = args[0].cast<Array<RequestStreamOutput>>();
184	      std::string responses = this->GetResponseFromStreamOutput(delta_outputs);
185	      this->request_stream_callback_(responses);
186	    };
187	
188	    request_stream_callback = Function(frequest_stream_callback_wrapper);
189	    this->engine_->InitThreadedEngine(device, std::move(request_stream_callback), std::nullopt);
190	  }
191	
192	  void Reload(String engine_config_json_str) {
193	    this->engine_->Reload(engine_config_json_str);
194	    this->default_generation_config_ = this->engine_->GetDefaultGenerationConfig();
195	    auto engine_config = this->engine_->GetCompleteEngineConfig();
196	
197	    // Load conversation template.
198	    Result<tvm::ffi::json::Object> model_config_json =
199	        serve::Model::LoadModelConfig(engine_config->model);
200	    TVM_FFI_ICHECK(model_config_json.IsOk()) << model_config_json.UnwrapErr();
201	    const tvm::ffi::json::Object& model_config_json_unwrapped = model_config_json.Unwrap();
202	    Result<Conversation> conv_template = Conversation::FromJSON(
203	        json::Lookup<tvm::ffi::json::Object>(model_config_json_unwrapped, "conv_template"));
204	    TVM_FFI_ICHECK(!conv_template.IsErr())
205	        << "Invalid conversation template JSON: " << conv_template.UnwrapErr();
206	    this->conv_template_ = conv_template.Unwrap();
207	    this->model_config_ = ModelConfig::FromJSON(
208	        json::Lookup<tvm::ffi::json::Object>(model_config_json_unwrapped, "model_config"));
209	    this->tokenizer_ = Tokenizer::FromPath(engine_config->model);
210	  }
211	
212	  void Unload() { this->engine_->Unload(); }
213	
214	  void Reset() { this->engine_->Reset(); }
215	
216	  void RunBackgroundLoop() { this->engine_->RunBackgroundLoop(); }
217	
218	  void RunBackgroundStreamBackLoop() { this->engine_->RunBackgroundStreamBackLoop(); }
219	
220	  String GetResponseFromStreamOutput(Array<RequestStreamOutput> delta_outputs) {
221	    tvm::ffi::json::Array json_response_arr;
222	    for (const auto& delta_output : delta_outputs) {
223	      std::string request_id = delta_output->request_id;
224	      auto request_state_it = request_map_.find(request_id);
225	      if (request_state_it == request_map_.end()) continue;
226	      RequestState& rstate = request_state_it->second;
227	
228	      // build the final usage messages
229	      // invariant, we can always let other messages to come first
230	      // then the final usage messages, as final usage is always last
231	      if (delta_output->request_final_usage_json_str.has_value()) {
232	        ChatCompletionStreamResponse response;
233	        response.id = request_id;
234	        response.model = rstate.model;
235	        response.system_fingerprint = "";
236	        std::string usage_json_str = delta_output->request_final_usage_json_str.value();
237	        tvm::ffi::String parse_err;
238	        auto usage_json = tvm::ffi::json::Parse(usage_json_str, &parse_err);
239	        if (!parse_err.empty()) {
240	          err_ = parse_err;
241	        } else {
242	          response.usage = usage_json;
243	        }
244	        json_response_arr.push_back(response.AsJSON());
245	        request_map_.erase(request_state_it);
246	        continue;
247	      }
248	      TVM_FFI_ICHECK_NE(delta_output->group_finish_reason.size(), 0);
249	      TVM_FFI_ICHECK_EQ(delta_output->group_delta_token_ids.size(),
250	                        delta_output->group_finish_reason.size());
251	      TVM_FFI_ICHECK_EQ(delta_output->group_delta_token_ids.size(), rstate.streamer.size());
252	
253	      ChatCompletionStreamResponse response;
254	      response.id = request_id;
255	      response.model = rstate.model;
256	      response.system_fingerprint = "";
257	
258	      for (size_t i = 0; i < delta_output->group_finish_reason.size(); ++i) {
259	        // choice
260	        ChatCompletionStreamResponseChoice choice;
261	        Optional<String> finish_reason = delta_output->group_finish_reason[i];
262	        if (finish_reason.has_value()) {
263	          if (finish_reason.value() == "stop") {
264	            choice.finish_reason = FinishReason::stop;
265	          } else if (finish_reason.value() == "length") {
266	            choice.finish_reason = FinishReason::length;
267	          } else if (finish_reason.value() == "tool_calls") {
268	            choice.finish_reason = FinishReason::tool_calls;
269	          } else if (finish_reason.value() == "error") {
270	            choice.finish_reason = FinishReason::error;
271	          }
272	        } else {
273	          choice.finish_reason = std::nullopt;
274	        }
275	        choice.index = static_cast<int>(i);
276	        ChatCompletionMessage delta;
277	        // Size of delta_output->group_delta_token_ids Array should be 1
278	        const Shape& delta_token_ids = delta_output->group_delta_token_ids[i];
279	        std::vector<int32_t> delta_token_ids_vec(delta_token_ids.begin(), delta_token_ids.end());
280	        std::string content = rstate.streamer[i]->Put(delta_token_ids_vec);
281	        if (finish_reason.has_value()) {
282	          content += rstate.streamer[i]->Finish();
283	        }
284	        if (!content.empty()) {
285	          delta.content = content;
286	        }
287	        delta.role = "assistant";
288	        choice.delta = delta;
289	        if (!choice.delta.content.IsNull() || choice.finish_reason.has_value()) {
290	          response.choices.push_back(choice);
291	        }
292	      }
293	      // if it is not the usage block, choices cannot be empty
294	      if (!response.choices.empty()) {
295	        json_response_arr.push_back(response.AsJSON());
296	      }
297	    }
298	    return tvm::ffi::json::Stringify(json_response_arr);
299	  }
300	};
301	
302	TVM_FFI_STATIC_INIT_BLOCK() {
303	  namespace refl = tvm::ffi::reflection;
304	  refl::GlobalDef().def("mlc.json_ffi.CreateJSONFFIEngine",
305	                        []() { return ffi::Module(tvm::ffi::make_object<JSONFFIEngineImpl>()); });
306	}
307	
308	}  // namespace json_ffi
309	}  // namespace llm
310	}  // namespace mlc
